 * @param {number} base - Monto económico bruto.
 * @returns {number} Valor total calculado incluyendo impuestos.
 */
function calcularTotalConImpuestos(base) {
    const impuesto = base * 0.21;
    const total = base + impuesto;

    // 'return' expulsa el valor final para que pueda ser almacenado o utilizado
    return total;

    // CUALQUIER código después de 'return' es ignorado por el motor de JavaScript
