// =========================================================
// 1. DEFINICIÓN DEL MOLDE (La Clase)
// =========================================================
class Vehiculo {
    // El constructor recibe los parámetros iniciales para personalizar cada objeto
    constructor(marca, modelo, color) {
        console.log(`Depuración - Ejecutando constructor para un nuevo ${marca}...`);

        // Asignamos los valores a las propiedades del objeto usando 'this'
        this.marca = marca;
        this.modelo = modelo;
        this.color = color;
        this.estaEncendido = false; // Propiedad inicial por defecto
    }

    // Método: Acción que todos los vehículos creados sabrán realizar
    encenderMotor() {
        this.estaEncendido = true;
        console.log(`Depuración - [${this.marca} ${this.modelo}]: El motor ha arrancado.`);
    }

    mostrarInformacion() {
        const estado = this.estaEncendido ? "Encendido" : "Apagado";
        console.log(`Vehículo: ${this.marca} ${this.modelo} | Color: ${this.color} | Estado: ${estado}`);
    }
}

// =========================================================
// 2. CREACIÓN DE INSTANCIAS (Objetos reales basados en el molde)
// =========================================================
console.log("Iniciando la fabricación de vehículos...\n");

// Creamos el primer objeto real (Instancia 1)
const miAuto = new Vehiculo("Toyota", "Corolla", "Rojo");

// Creamos un segundo objeto completamente independiente (Instancia 2)
const autoCliente = new Vehiculo("Hyundai", "i30", "Gris");

// =========================================================
// 3. USO DE LAS INSTANCIAS Y DEPURACIÓN
// =========================================================
console.log("\n--- Interactuando con las instancias ---");

// Cada objeto mantiene su propio estado de forma aislada
miAuto.encenderMotor();
miAuto.mostrarInformacion();

// El segundo objeto sigue apagado porque no hemos llamado a su método
autoCliente.mostrarInformacion();

// =========================================================
// PILAR 1 Y 2: ENCAPSULAMIENTO Y ABSTRACCIÓN
// =========================================================
class CuentaBancaria {
    // Propiedad privada (#): Nadie puede modificarla directamente desde fuera
    #saldo;

    constructor(titular, saldoInicial) {
        this.titular = titular;
        this.#saldo = saldoInicial;
    }

    // Abstracción: El exterior solo ve el método simplificado 'depositar'
    depositar(monto) {
        if (monto > 0) {
            this.#saldo += monto;
            console.log(`Depuración - [Cuenta de ${this.titular}]: Depósito de $${monto} procesado con éxito.`);
        } else {
            console.log("⚠️ Error: El monto a depositar debe ser mayor a cero.");
        }
    }

    // Mecanismo seguro (Getter) para exponer el valor privado bajo control
    obtenerSaldoActual() {
        return this.#saldo;
    }
}

// =========================================================
// PILAR 3 Y 4: HERENCIA Y POLIMORFISMO
// =========================================================
// Clase Padre (Base)
class Empleado {
    constructor(nombre, salarioBase) {
        this.nombre = nombre;
        this.salarioBase = salarioBase;
    }

    // Método base que será polimorfado
    calcularPago() {
        return this.salarioBase;
    }
}

// Herencia: Desarrollador hereda de Empleado usando 'extends'
class Desarrollador extends Empleado {
    constructor(nombre, salarioBase, bonoProyecto) {
        // 'super' inicializa las propiedades heredadas del padre
        super(nombre, salarioBase);
        this.bonoProyecto = bonoProyecto;
    }

    // Polimorfismo: Sobreescribimos el método 'calcularPago' con lógica propia
    calcularPago() {
        console.log(`Depuración - Calculando nómina especial para Desarrollador: ${this.nombre}`);
        return this.salarioBase + this.bonoProyecto;
    }
}

// =========================================================
// PRUEBAS DE EJECUCIÓN Y DEPURACIÓN
// =========================================================
console.log("--- Probando Encapsulamiento ---");
const miCuenta = new CuentaBancaria("Juan Pérez", 500);
miCuenta.depositar(200);
// miCuenta.#saldo = 1000000; // ❌ ERROR: Provoca fallo sintáctico, el saldo está protegido
console.log("Saldo final verificado:", miCuenta.obtenerSaldoActual());

console.log("\n--- Probando Herencia y Polimorfismo ---");
const empleadoComun = new Empleado("Ana Gómez", 1500);
const desarrolladorSenior = new Desarrollador("Carlos Ruiz", 2500, 600);

// Ambos responden al mismo método, pero ejecutan cálculos distintos (Polimorfismo)
console.log(`Pago de Ana: $${empleadoComun.calcularPago()}`);
console.log(`Pago de Carlos: $${desarrolladorSenior.calcularPago()}`);

// =========================================================
