console.log("Depuración - Elemento botón capturado:", boton);

// Comprobación de seguridad para evitar fallos si el HTML cambia
if (titulo && boton) {

    // 2. MODIFICACIÓN DINÁMICA DE CONTENIDO
    // Cambiamos el texto interno de forma segura
    titulo.textContent = "¡Interfaz Actualizada con JavaScript!";
