    // 3. MODIFICACIÓN DIRECTA DE ESTILOS CSS (Estilos Inline)
    // Se utiliza la nomenclatura camelCase para propiedades CSS compuestas
    titulo.style.color = "#2ecc71"; // Cambia el color a verde
    titulo.style.backgroundColor = "#f8f9fa"; // Cambia el fondo
    titulo.style.padding = "15px";

    // 4. MEJOR PRÁCTICA: MANIPULACIÓN DE CLASES (classList)
    // En lugar de tocar estilos uno a uno, añadimos una clase CSS predefinida
    boton.classList.add("btn-activo");

    // El método toggle añade la clase si no existe, o la quita si ya existe
    boton.classList.toggle("animacion-pulso");

    console.log("Depuración - Clases actuales del botón:", boton.className);

} else {
    console.log("⚠️ Alerta: No se encontraron los elementos en el árbol DOM actual.");
}

// =========================================================
// REPRESENTACIÓN DEL HTML REQUISITO PARA ESTE CÓDIGO:
// <div id="contenedor-padre">
//     <ul id="lista-tareas">
//         <li class="tarea">Comprar pan <button class="btn-borrar">Eliminar</button></li>
//     </ul>
// </div>
// =========================================================

console.log("Depuración - Iniciando el sistema de eventos avanzados...");

const padre = document.querySelector("#contenedor-padre");
const lista = document.querySelector("#lista-tareas");

// 1. DEMOSTRACIÓN DE PROPAGACIÓN (BUBBLING) Y CÓMO DETENERLA
if (padre) {
    padre.addEventListener("click", (event) => {
        // Este log se ejecutará por el efecto burbuja si hacemos clic en sus hijos
        console.log("Depuración - [Burbujeo]: El evento llegó hasta el DIV PADRE.");
    });
}

// 2. TÉCNICA PROFESIONAL: DELEGACIÓN DE EVENTOS
if (lista) {
    // En lugar de escuchar cada botón individual, escuchamos únicamente a la lista entera
    lista.addEventListener("click", (event) => {
        console.log("\nDepuración - Clic detectado en el componente Lista.");
        console.log("Depuración - Elemento exacto que recibió el clic (target):", event.target);

        // Comprobamos si el elemento real que fue clickeado es el botón de borrar
        if (event.target.classList.contains("btn-borrar")) {
            console.log("Depuración - Filtro correcto: El usuario quiere eliminar un elemento.");

            // Detenemos la propagación para que el DIV PADRE no reciba el impacto por accidente
            event.stopPropagation();
            console.log("Depuración - Propagación frenada con stopPropagation().");

            // Localizamos el nodo 'li' (tarea) más cercano al botón para proceder al borrado
            const elementoTarea = event.target.closest(".tarea");
            if (elementoTarea) {
                elementoTarea.remove();
                console.log("Depuración - Elemento del DOM eliminado correctamente.");
            }
        }
    });
}

// =========================================================
// 1. GUARDAR Y RECUPERAR DATOS SIMPLES (TEXTO)
