function crearContador() {
    // Esta variable está protegida dentro del ámbito de la función padre
    let contadorPrivado = 0;

    console.log("Depuración - Fábrica inicializada. Variable local fijada en 0.");

    // Retornamos la función hija. Esta función es el Closure.
    return function() {
        contadorPrivado++; // Incrementa la variable de la función padre
        console.log(`Depuración [Closure] -> Accediendo a la mochila. Valor actual: ${contadorPrivado}`);
        return contadorPrivado;
    };
}

