// 1. SIMULACIÓN DE UNA PETICIÓN ASÍNCRONA (Base con Promesas)
// =========================================================
const simularServidorBaseDatos = (usuarioId) => {
    // Retornamos una nueva promesa encargada de la tarea en segundo plano
    return new Promise((resolve, reject) => {
        console.log(`\nDepuración - [Servidor]: Buscando al usuario ${usuarioId} en la base de datos...`);

        // Simulamos un retraso de red de 2 segundos mediante setTimeout
        setTimeout(() => {
            const exito = true; // Cambiar a false para probar el flujo de error (.catch)

            if (exito) {
                // Si todo sale bien, resolvemos la promesa enviando un objeto con los datos
                resolve({ id: usuarioId, nombre: "Carlos Code", rol: "Developer" });
            } else {
                // Si algo falla, rechazamos la promesa enviando un mensaje de error
                reject("Error 500: No se pudo conectar con la base de datos.");
            }
        }, 2000);
    });
};

// =========================================================
// 2. CONSUMO DE LA PROMESA USANDO ASYNC / AWAIT (Estándar Profesional)
// =========================================================
const procesarSolicitudUsuario = async () => {
    console.log("Depuración - [Cliente]: Iniciando proceso de login...");

    // Para capturar errores en bloques async/await, es obligatorio envolver el código en un try/catch
    try {
        // 'await' congela temporalmente esta línea hasta que la promesa del servidor se resuelva
        const usuarioRecuperado = await simularServidorBaseDatos(402);

        console.log("Depuración - [Cliente]: Datos recibidos con éxito del await.");
        console.log(`¡Bienvenido de nuevo, ${usuarioRecuperado.nombre}! Tu rol asignado es: ${usuarioRecuperado.rol}`);

    } catch (error) {
        // Si la promesa es rechazada, el flujo salta directamente a este bloque
        console.log("⚠️ Alerta en el bloque catch:", error);
    } finally {
        console.log("Depuración - Proceso finalizado (Este bloque se ejecuta siempre, haya éxito o fallo).");
    }
};

// Ejecutamos la función asíncrona principal
procesarSolicitudUsuario();
console.log("Depuración - [Hilo Principal]: Yo no espero a nadie, sigo ejecutando líneas de código en paralelo.");

