// 1. Código síncrono: entra directo al Call Stack y se ejecuta inmediatamente.
console.log("Depuración [1]: Inicio del script (Código síncrono).");

// 2. Macrotarea: se delega a las Web APIs del navegador.
// Aunque el tiempo es 0ms, su callback debe esperar obligatoriamente en la Callback Queue.
setTimeout(() => {
    console.log("Depuración [2]: Ejecutando callback de setTimeout (Macrotarea).");
}, 0);

// 3. Microtarea: se procesa e introduce su resolución en la Microtask Queue.
Promise.resolve()
    .then(() => {
        console.log("Depuración [3]: Ejecutando resolución de Promesa 1 (Microtarea).");
    })
    .then(() => {
        // Las microtareas encadenadas se ejecutan de forma consecutiva antes de ceder el turno
        console.log("Depuración [4]: Ejecutando segunda Promesa consecutiva (Microtarea).");
    });

// 4. Última línea síncrona: se ejecuta antes de que el Call Stack quede vacío.
console.log("Depuración [5]: Fin del script (Código síncrono).");

