// Función simulada que retorna una Promesa para emular una petición de red externa
const obtenerDatosUsuario = (idUsuario) => {
    return new Promise((resolve, reject) => {
        console.log(`Depuración - [Web API]: Iniciando temporizador asíncrono para usuario ID: ${idUsuario}`);

        setTimeout(() => {
            const exito = true; // Modificar a false para simular un fallo de red y evaluar el bloque catch

            if (exito) {
                // La promesa se resuelve con éxito devolviendo el objeto de datos
                resolve({ id: idUsuario, nombre: "Carlos Gómez", rol: "Developer" });
            } else {
                // La promesa es rechazada arrojando un error formal
                reject(new Error("Error de conexión: No se pudo conectar con el servidor remoto."));
            }
        }, 1500);
    });
};

// Función asíncrona principal encargada de orquestar el flujo de datos
const procesarPerfilSocio = async (id) => {
    console.log("Depuración - [Función Async]: Ejecutando bloque de inicialización...");

    try {
        console.log("Depuración - [Try]: Solicitando datos al servidor. El hilo se pausará localmente sin bloquear la app.");

        // El operador 'await' detiene la ejecución interna hasta que la promesa de obtenerDatosUsuario se resuelva
        const usuario = await obtenerDatosUsuario(id);

        console.log("Depuración - [Try]: Datos recibidos de forma exitosa desde la Promesa.");
        console.log("Resultado del Perfil de Usuario:", usuario);

    } catch (error) {
        // Este bloque intercepta cualquier rechazo de la promesa o fallo inesperado de ejecución
        console.log("⚠️ Alerta de Error en el Bloque Catch:", error.message);

    } finally {
        // Este bloque se ejecuta de forma obligatoria sin importar si hubo éxito o fallo en el bloque try
        console.log("Depuración - [Finally]: Limpieza de recursos y cierre de conexiones finalizado con éxito.");
    }
};

// Ejecución del flujo general del programa
console.log("Depuración - [Código Síncrono]: Iniciando llamada principal del script.");
procesarPerfilSocio(101);
