// URL pública de pruebas que simula una API de usuarios en producción
const URL_API_USUARIOS = "https://jsonplaceholder.typicode.com/users/1";

const consultarDatosServidor = async () => {
    console.log("Depuración [1]: Preparando el entorno para iniciar la petición de red...");

    try {
        console.log("Depuración [2]: Lanzando petición HTTP GET mediante fetch()...");
        // Paso 1: Esperamos la respuesta inicial del servidor (Cabeceras y Estado)
        const respuesta = await fetch(URL_API_USUARIOS);

        console.log("Depuración [3]: Conexión establecida. Estado HTTP recibido:", respuesta.status);

        // VALIDACIÓN CRUCIAL: Verificamos si el servidor respondió con un estado de éxito (200-299)
        if (!respuesta.ok) {
            // Lanzamos un error manualmente si el estado no es satisfactorio (ej. 404 o 500)
            throw new Error(`Fallo en la comunicación. Código de estado del servidor: ${respuesta.status}`);
        }

        console.log("Depuración [4]: El estado es correcto. Extrayendo el cuerpo de los datos en formato JSON...");
        // Paso 2: Descargamos y parseamos el contenido real del mensaje de forma asíncrona
        const datosUsuario = await respuesta.json();

        console.log("Depuración [5]: Datos procesados y transformados a objeto de JavaScript con éxito.");
        console.log("Resultado final del perfil solicitado:", datosUsuario);

    } catch (error) {
        // Este bloque interceptará fallos reales de red (como quedarse sin internet) o errores lanzados en el 'throw'
        console.log("⚠️ Alerta en el bloque catch (Error de Red o Servidor):", error.message);

    } finally {
        console.log("Depuración [6]: Operación de consulta HTTP finalizada de forma segura.");
    }
};

// Ejecutamos el flujo de consulta externa
