// Función profesional encargada de procesar un archivo de configuración
const procesarConfiguracion = (configJson) => {
    console.log("Depuración [1]: Iniciando análisis del archivo de configuración...");

    try {
        console.log("Depuración [2]: Intentando parsear la cadena JSON...");

        // Si el JSON es inválido o está mal formado, JSON.parse() lanzará un error automáticamente
        const configuracion = JSON.parse(configJson);

        // Validación de negocio manual
        if (!configuracion.version) {
            // Lanzamos un error personalizado de forma explícita si falta un campo crítico
            throw new Error("El archivo de configuración no cuenta con una versión válida.");
        }

        console.log("Depuración [3]: Configuración procesada con éxito:", configuracion);
        return configuracion;

    } catch (error) {
        // Este bloque intercepta cualquier error lanzado en el bloque 'try'
        console.error("⚠️ Error interceptado en el bloque Catch:");
        console.error(`- Tipo de Error: ${error.name}`);
        console.error(`- Mensaje detallado: ${error.message}`);

        // Retornamos un objeto por defecto (fallback) para que la aplicación continúe funcionando
        return { version: "1.0.0", fallback: true };

    } finally {
        // Este bloque se ejecuta SIEMPRE, garantizando la limpieza del entorno de ejecución
        console.log("Depuración [4]: Bloque Finally ejecutado. Operación de lectura cerrada de forma segura.");
    }
};

