    constructor(usuarioRepositorio) {
        this.#repositorio = usuarioRepositorio;
    }
    #repositorio;

    obtenerPerfilProcesado(id) {
        console.log("Depuración [Servicio]: Iniciando procesamiento y reglas de negocio...");

        // 1. Delegamos la obtención de datos estrictamente al repositorio
        const usuario = this.#repositorio.buscarPorId(id);

        if (!usuario) {
            console.log(`Depuración [Servicio]: Regla fallida -> Usuario con ID ${id} no existe.`);
