// --- CAPA DE DATOS: REPOSITORIO ---
class PedidoRepository {
    constructor() {
        this.#pedidosContenedor = [];
    }
    #pedidosContenedor;

    // Guarda de forma definitiva el objeto del pedido formateado
    guardarNuevoPedido(pedidoDb) {
        console.log("Depuración [3 - Repositorio]: Recibiendo datos desde el Servicio para persistencia...");
        this.#pedidosContenedor.push(pedidoDb);

        console.log("Depuración [3 - Repositorio]: Guardado exitoso. Contenido actual de la BD:", this.#pedidosContenedor);
        return { ...pedidoDb, guardadoConfirmado: true };
    }
}

// --- CAPA DE NEGOCIO: SERVICIO ---
class PedidoService {
    // Recibe el repositorio por inversión de dependencias
    constructor(pedidoRepo) {
        this.#repo = pedidoRepo;
    }
    #repo;

    // Procesa las reglas comerciales e introduce lógica adicional antes de guardar
    crearYValidarPedido(datosBrutos) {
        console.log("Depuración [2 - Servicio]: Datos recibidos del Controlador. Validando reglas comerciales...");

        // Regla de Negocio: Validar que el monto mínimo sea superior a 0
        if (datosBrutos.total <= 0) {
            console.log("Depuración [2 - Servicio]: Regla fallida -> Monto del pedido inválido.");
            throw new Error("El total del pedido debe ser una cantidad positiva mayor a cero.");
        }

        console.log("Depuración [2 - Servicio]: Reglas aprobadas. Estructurando entidad de base de datos...");
        const pedidoFormateado = {
            idPedido: Math.floor(Math.random() * 10000),
            item: datosBrutos.item,
            total: datosBrutos.total,
            fechaRegistro: new Date().toISOString()
        };

        // Transferencia del flujo a la capa de datos
        const resultadoPersistencia = this.#repo.guardarNuevoPedido(pedidoFormateado);

        console.log("Depuración [2 - Servicio]: Datos retornados del Repositorio. Enviando respuesta al Controlador...");
        return resultadoPersistencia;
    }
}

// --- CAPA DE ENTRADA: CONTROLADOR ---
class PedidoController {
    // Se comunica únicamente con el Servicio correspondiente
    constructor(pedidoServ) {
        this.#servicio = pedidoServ;
    }
    #servicio;

    // Gestiona el ciclo completo de la petición y respuesta de red externa
    postCrearPedido(peticionHttp) {
        console.log(`\nDepuración [1 - Controlador]: Petición POST recibida para el artículo: "${peticionHttp.body.item}"`);

        try {
            // Traspaso de los datos crudos del cuerpo de la petición hacia el servicio
            const respuestaNegocio = this.#servicio.crearYValidarPedido(peticionHttp.body);

            console.log("Depuración [1 - Controlador]: Operación exitosa. Despachando Respuesta HTTP 201 Creación.");
            return { codigoEstado: 201, mensaje: "Pedido procesado con éxito", datos: respuestaNegocio };

        } catch (error) {
            console.log(`Depuración [1 - Controlador]: Excepción atrapada desde capas inferiores -> "${error.message}"`);
            console.log("Depuración [1 - Controlador]: Despachando Respuesta HTTP 400 Bad Request.");
            return { codigoEstado: 400, mensajeError: error.message };
        }
    }
}

