/**
 * Clase Controlador encargada estrictamente del ciclo de petición y respuesta HTTP.
 */
class ProductoController {
    // Inyección de dependencias obligatoria: solo se comunica con el servicio
    constructor(productoService) {
        this.#servicio = productoService;
    }
    #servicio;

    /**
     * Gestiona la creación de un nuevo producto (Simula un endpoint POST /productos)
     * @param {Object} req - Objeto de petición HTTP (Request)
     * @returns {Object} Objeto de respuesta HTTP (Response) con estado y cuerpo
     */
    postCrearProducto(req) {
        console.log("\nDepuración [Controlador]: Petición POST recibida en la ruta '/productos'.");
        console.log("Depuración [Controlador]: Datos crudos del cuerpo (body):", req.body);

        try {
            // 1. Validación de entrada sintáctica básica (Responsabilidad del Controlador)
            if (!req.body || !req.body.nombre) {
                console.log("Depuración [Controlador]: Error de validación de entrada - Falta el campo 'nombre'.");
                return {
                    status: 400,
                    body: { error: "Bad Request", mensaje: "El campo 'nombre' es obligatorio para registrar un producto." }
                };
            }

            console.log("Depuración [Controlador]: Validación sintáctica correcta. Traspasando flujo al Servicio...");

            // 2. Delegación unidireccional del flujo a la capa de negocio
            const nuevoProducto = this.#servicio.crearProducto(req.body);

            // 3. Construcción de la respuesta HTTP exitosa (201 Created)
            console.log("Depuración [Controlador]: Servicio ejecutado con éxito. Preparando Respuesta HTTP 201.");
            return {
                status: 201,
                body: { mensaje: "Producto registrado con éxito", datos: nuevoProducto }
            };

        } catch (error) {
            // 4. Captura y traducción de excepciones a códigos de estado HTTP semánticos
            console.log(`Depuración [Controlador]: Excepción detectada -> "${error.message}"`);

            if (error.message.includes("VALIDACION_NEGOCIO")) {
                console.log("Depuración [Controlador]: Traduciendo error de negocio a HTTP 400 (Bad Request).");
                return {
                    status: 400,
                    body: { error: "Petición Incorrecta", mensaje: error.message.replace("VALIDACION_NEGOCIO: ", "") }
                };
            }

            console.log("Depuración [Controlador]: Error desconocido. Traduciendo a HTTP 500 (Internal Server Error).");
            return {
                status: 500,
                body: { error: "Internal Server Error", mensaje: "Ocurrió un error inesperado en el servidor." }
                };
        }
    }
}

