/**
 * Capa Servicio: Centraliza de forma estricta las reglas comerciales de la aplicación.
 */
class SocioService {
    // El repositorio se inyecta en el constructor, impidiendo el acoplamiento rígido
    constructor(socioRepository) {
        this.#repository = socioRepository;
    }
    #repository;

    /**
     * Registra un nuevo miembro aplicando las reglas de negocio de la compañía
     * @param {Object} datosSocio - Información cruda y validada sintácticamente por el controlador
     * @returns {Object} Entidad final guardada e indexada
     */
    registrarNuevoSocio(datosSocio) {
        console.log("\nDepuración [Servicio]: Iniciando ejecución del caso de uso (Registrar Socio).");
        console.log("Depuración [Servicio]: Evaluando políticas comerciales de la empresa...");

        // 1. Regla de Negocio: Restringir cuentas con correos duplicados
        const socioExistente = this.#repository.buscarPorEmail(datosSocio.email);
        if (socioExistente) {
            console.log(`Depuración [Servicio]: Regla infringida -> El correo ${datosSocio.email} ya está en uso.`);
            throw new Error("NEGOCIO_ERROR: El correo electrónico ya se encuentra registrado en el sistema.");
        }

        // 2. Regla de Negocio: Validación de edad mínima requerida por normativas legales
        if (datosSocio.edad < 18) {
            console.log(`Depuración [Servicio]: Regla infringida -> Edad de ${datosSocio.edad} años es insuficiente.`);
            throw new Error("NEGOCIO_ERROR: El solicitante debe ser mayor de edad para adquirir la membresía.");
        }

        // 3. Lógica de negocio avanzada: Clasificación automatizada según el monto de apertura
        console.log("Depuración [Servicio]: Ejecutando algoritmo de asignación de categorías...");
        let categoriaMembresia = "Estándar";
        if (datosSocio.montoApertura >= 500) {
            categoriaMembresia = "Premium";
            console.log("Depuración [Servicio]: Regla aplicada -> Otorgando estatus Premium por inversión inicial.");
        }

        // Estructuración de la Entidad de Dominio limpia antes de guardarla
        const entidadParaPersistir = {
            nombre: datosSocio.nombre,
            email: datosSocio.email,
            edad: datosSocio.edad,
            membresia: categoriaMembresia,
            estado: "Activo"
        };

        // 4. Delegación del flujo de datos hacia la capa inferior de persistencia
        console.log("Depuración [Servicio]: Todas las reglas aprobadas. Delegando almacenamiento al Repositorio...");
        const socioGuardado = this.#repository.guardar(entidadParaPersistir);

        console.log("Depuración [Servicio]: Flujo de negocio finalizado con éxito. Retornando entidad al Controlador.");
        return socioGuardado;
    }
}

