/**
 * Capa Repositorio: Encapsula el acceso directo y la persistencia de los datos.
 * Sigue el patrón de producción aislando el origen de datos del resto de la app.
 */
class UsuarioRepository {
    // Simulación de una tabla física de base de datos protegida de forma privada
    #tablaUsuarios = [
        { id: 1, email: "alumno1@correo.com", activo: true },
        { id: 2, email: "alumno2@correo.com", activo: false }
    ];

    /**
     * Busca un registro específico en la base de datos por su identificador único
     * @param {number} id - Identificador del usuario
     * @returns {Object|null} Devuelve la entidad encontrada o null si no existe
     */
    findById(id) {
        console.log(`Depuración [Repositorio - findById]: Ejecutando consulta física en la BD para ID: ${id}`);

        const resultado = this.#tablaUsuarios.find(u => u.id === id);

        // Retornamos una copia profunda para evitar que se modifiquen los datos de la BD por referencia
        return resultado ? { ...resultado } : null;
    }

    /**
     * Inserta un nuevo registro de forma permanente en el almacenamiento
     * @param {Object} entidadUsuario - Datos de la entidad mapeada
     * @returns {Object} Devuelve el registro final tal como quedó guardado con su ID asignado
     */
    save(entidadUsuario) {
        console.log("Depuración [Repositorio - save]: Abriendo conexión de escritura con el motor de datos...");

        const nuevoId = this.#tablaUsuarios.length + 1;
        const registroGuardado = {
            id: nuevoId,
            email: entidadUsuario.email,
            activo: true,
            creadoEl: new Date().toISOString()
        };

        // Inserción física en la estructura de persistencia
        this.#tablaUsuarios.push(registroGuardado);
        console.log("Depuración [Repositorio - save]: Operación de persistencia completada con éxito.");

        return { ...registroGuardado };
    }
}

