/**
 * Capa de Servicio que consume el repositorio mediante Inversión de Dependencias.
 * El servicio aplica la lógica de negocio sobre los datos que le provee el repositorio.
 */
class UsuarioService {
    constructor(usuarioRepo) {
        this.#repo = usuarioRepo; // Inyección de la capa de persistencia
    }
    #repo;

    obtenerDatosSeguros(id) {
        console.log(`\nDepuración [Servicio]: Procesando caso de uso para consultar ID: ${id}`);

        // Llamada limpia al repositorio: el servicio desconoce cómo busca el repositorio en la BD
        const usuario = this.#repo.findById(id);

        if (!usuario) {
            console.log("Depuración [Servicio]: Validación fallida, el repositorio retornó null.");
            throw new Error("El usuario solicitado no existe en los registros de la empresa.");
        }

        if (!usuario.activo) {
            console.log("Depuración [Servicio]: Regla de negocio infringida. Usuario inactivo.");
            throw new Error("La cuenta del usuario se encuentra suspendida temporalmente.");
        }

        console.log("Depuración [Servicio]: Reglas comerciales aprobadas de forma exitosa.");
        return usuario;
    }
}

