/**
 * Capa Repositorio (Infraestructura)
 * Se encarga única y exclusivamente de la persistencia física de la información.
 */
class PedidoRepository {
    guardarEnBaseDatos(entidadPedido) {
        console.log(`Depuración [Repositorio]: Conectando a la BD para insertar el pedido #${entidadPedido.id}...`);
        return { ...entidadPedido, guardado: true, registradoEl: new Date().toISOString() };
    }
}

/**
 * Capa Servicio (Negocio)
 * Aplica las reglas comerciales. No instancia el repositorio internamente (evita acoplamiento).
 * Recibe la dependencia ya lista desde el exterior a través del constructor.
 */
class PedidoService {
    #repository;

    // El Repositorio se inyecta de forma dinámica aquí
    constructor(pedidoRepository) {
        console.log("Depuración [Servicio]: Recibiendo e inyectando la instancia del Repositorio.");
        this.#repository = pedidoRepository;
    }

    procesarPedido(datosCrudos) {
        console.log("\nDepuración [Servicio]: Evaluando políticas y reglas de negocio del pedido...");

        // Algoritmo de negocio: Cálculo estricto de impuestos de la empresa
        const totalConImpuesto = datosCrudos.precio * 1.21;

        const entidadPedido = {
            id: Math.floor(Math.random() * 10000),
            articulo: datosCrudos.articulo,
            total: parseFloat(totalConImpuesto.toFixed(2))
        };

        console.log("Depuración [Servicio]: Reglas aprobadas. Delegando el almacenamiento al Repositorio inyectado.");
        return this.#repository.guardarEnBaseDatos(entidadPedido);
    }
}

/**
 * Capa Controlador (Comunicación)
 * Gestiona la entrada HTTP. Recibe el Servicio por inyección. Jamás conoce al Repositorio.
 */
class PedidoController {
    #service;

    // El Servicio se inyecta de forma dinámica aquí
    constructor(pedidoService) {
        console.log("Depuración [Controlador]: Recibiendo e inyectando la instancia del Servicio.");
        this.#service = pedidoService;
    }

    // Simulación del punto de acceso (Endpoint) de la aplicación
    recibirPeticionAltaPedido(requestBody) {
        console.log("\nDepuración [Controlador]: Petición HTTP POST capturada. Delegando flujo al Servicio.");

        try {
            const resultadoFinal = this.#service.procesarPedido(requestBody);
            console.log("Depuración [Controlador]: Flujo completado con éxito. Respondiendo HTTP 201 Created.");
            return { statusCode: 201, body: resultadoFinal };
        } catch (error) {
            console.error("Depuración [Controlador]: Excepción atrapada en el flujo:", error.message);
            return { statusCode: 500, error: error.message };
        }
    }
}

