/**
 * CAPA REPOSITORIO (Persistencia limpia)
 * Encargada únicamente de la lectura y escritura cruda en el origen de datos.
 */
class LicenciaRepository {
    #tablaLicencias = [
        { id: 101, usuario: "Socio Pro", activa: true, diasRestantes: 5 },
        { id: 102, usuario: "Socio Básico", activa: false, diasRestantes: 0 }
    ];

    obtenerPorId(id) {
        console.log(`[Depuración - Repositorio]: Consultando registro físico de la licencia #${id}`);
        const licencia = this.#tablaLicencias.find(item => item.id === id);
        return licencia ? { ...licencia } : null;
    }

    actualizarDiasValidez(id, nuevosDias) {
        console.log(`[Depuración - Repositorio]: Actualizando base de datos. ID: ${id} -> Nuevos días: ${nuevosDias}`);
        const licenciaOriginal = this.#tablaLicencias.find(item => item.id === id);

        if (licenciaOriginal) {
            licenciaOriginal.diasRestantes = nuevosDias;
            licenciaOriginal.activa = true;
            return { ...licenciaOriginal };
        }
        return null;
    }
}

/**
 * CAPA SERVICIO (Cerebro del Negocio)
 * Aplica Clean Code: nombres de funciones semánticos, funciones cortas y legibles.
 */
class LicenciaService {
    #repository; // Inyección por constructor para mantener el desacoplamiento

    constructor(licenciaRepo) {
        this.#repository = licenciaRepo;
    }

    /**
     * Caso de uso: Extiende la validez de una licencia aplicando políticas comerciales
     */
    extenderVencimiento(idLicencia, diasAñadir) {
        console.log(`[Depuración - Servicio]: Iniciando lógica de negocio para extender licencia #${idLicencia}`);

        // 1. Refactorización: Validación temprana (Fail Fast) para evitar anidaciones innecesarias de 'if'
        if (diasAñadir <= 0) {
            console.log("[Depuración - Servicio]: Validación fallida -> Días inválidos sugeridos.");
            throw new Error("NEGOCIO: La cantidad de días a añadir debe ser un número entero positivo.");
        }

        const licencia = this.#repository.obtenerPorId(idLicencia);
        if (!licencia) {
            console.log(`[Depuración - Servicio]: Validación fallida -> Licencia #${idLicencia} inexistente.`);
            throw new Error("NEGOCIO: No se encontró ninguna licencia registrada con el identificador provisto.");
        }

        // 2. Extracción de algoritmo: Cálculo limpio del nuevo periodo de vigencia
        const nuevoPeriodoVencimiento = licencia.diasRestantes + diasAñadir;

        console.log(`[Depuración - Servicio]: Reglas comerciales aprobadas. Nuevo total calculado: ${nuevoPeriodoVencimiento} días.`);

        // 3. Delegación unidireccional del almacenamiento de datos
        return this.#repository.actualizarDiasValidez(idLicencia, nuevoPeriodoVencimiento);
    }
}

/**
 * CAPA CONTROLADOR (Punto de entrada de peticiones externas)
 * No maneja lógica de datos ni de negocio. Controla estrictamente los flujos try-catch.
 */
class LicenciaController {
    #service; // Depende únicamente de la capa intermedia de servicio

    constructor(licenciaService) {
        this.#service = licenciaService;
    }

    /**
     * Mapea y atiende la solicitud de actualización
     */
    putRenovarLicencia(req) {
        const { licenciaId, dias } = req.body;
        console.log(`\n[Depuración - Controlador]: Petición PUT recibida para renovar Licencia #${licenciaId} (+${dias} días)`);

        try {
            // Delegación directa al servicio ejecutor
            const licenciaActualizada = this.#service.extenderVencimiento(licenciaId, dias);

            console.log("[Depuración - Controlador]: Procesamiento exitoso. Despachando código HTTP 200 Ok.");
            return { statusCode: 200, body: { exito: true, data: licenciaActualizada } };

        } catch (error) {
            console.log(`[Depuración - Controlador]: Excepción interceptada en la ejecución -> "${error.message}"`);

            // Tratamiento semántico de errores para el cliente final
            if (error.message.startsWith("NEGOCIO:")) {
                return { 
                    statusCode: 400, 
                    body: { error: "Petición Errónea", detalle: error.message.replace("NEGOCIO: ", "") } 
                };
            }

            return { 
                statusCode: 500, 
                body: { error: "Error Interno", detalle: "Ocurrió un error inesperado al procesar la renovación." } 
            };
        }
    }
}

